import './ToDoList.css';
import React, { useState } from 'react';

const ToDoList = (props) => {
    var [checked,setChecked] = useState("glyphicon-unchecked");
    return (
        <>
            <div className="Todolist">
                <span className='Todoicon'>X</span>
                <span className="Todotext">{props.text}</span>
                <span class="glyphicon {checked}"></span>
            </div>
        </>
    );
}

export default ToDoList;
